(175,'_site_transient_wp_plugin_dependencies_plugin_data','a:1:{s:14:\"contact-form-7\";a:35:{s:4:\"name\";s:14:\"Contact Form 7\";s:4:\"slug\";s:14:\"contact-form-7\";s:7:\"version\";s:5:\"6.1.5\";s:6:\"author\";s:78:\"<a href=\"https://profiles.wordpress.org/rocklobsterinc/\">Rock Lobster Inc.</a>\";s:14:\"author_profile\";s:46:\"https://profiles.wordpress.org/rocklobsterinc/\";s:12:\"contributors\";a:2:{s:14:\"rocklobsterinc\";a:3:{s:7:\"profile\";s:46:\"https://profiles.wordpress.org/rocklobsterinc/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/4aa558df1c07e327536d8d0adad6d00fcdca0484c51adf0b867a2aa5ee054bbc?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:17:\"Rock Lobster Inc.\";}s:12:\"takayukister\";a:3:{s:7:\"profile\";s:44:\"https://profiles.wordpress.org/takayukister/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/538487024e649d43dea84ff38d14582d03119e3e7aaaca3b7692443335999133?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:16:\"Takayuki Miyoshi\";}}s:8:\"requires\";s:3:\"6.7\";s:6:\"tested\";s:5:\"6.9.4\";s:12:\"requires_php\";s:3:\"7.4\";s:16:\"requires_plugins\";a:0:{}s:6:\"rating\";i:80;s:7:\"ratings\";a:5:{i:5;i:1458;i:4;i:151;i:3;i:75;i:2;i:68;i:1;i:404;}s:11:\"num_ratings\";i:2156;s:11:\"support_url\";s:52:\"https://wordpress.org/support/plugin/contact-form-7/\";s:15:\"support_threads\";i:56;s:24:\"support_threads_resolved\";i:24;s:15:\"active_installs\";i:10000000;s:12:\"last_updated\";s:21:\"2026-02-08 9:32am GMT\";s:5:\"added\";s:10:\"2007-08-02\";s:8:\"homepage\";s:25:\"https://contactform7.com/\";s:8:\"sections\";a:6:{s:11:\"description\";s:2525:\"<p>Contact Form 7 is a plugin designed to be a practical tool for all WordPress users who embrace the philosophy of free and open source software. It employs sophisticatedly modularized architecture and its original <a href=\"https://contactform7.com/schema-woven-validation/\" rel=\"nofollow ugc\">Schema-Woven Validation</a> technology.</p>\n<h4>Docs and support</h4>\n<p>You can find <a href=\"https://contactform7.com/docs/\" rel=\"nofollow ugc\">docs</a>, <a href=\"https://contactform7.com/faq/\" rel=\"nofollow ugc\">FAQ</a> and more detailed information about Contact Form 7 on <a href=\"https://contactform7.com/\" rel=\"nofollow ugc\">contactform7.com</a>. When you cannot find the answer to your question on the FAQ or in any of the documentation, check the <a href=\"https://wordpress.org/support/plugin/contact-form-7/\" rel=\"ugc\">support forum</a> on WordPress.org. If you cannot locate any topics that pertain to your particular issue, post a new topic for it.</p>\n<h4>Contact Form 7 needs your support</h4>\n<p>It is hard to continue to maintain this plugin without support from users like you. There are several ways for you to <a href=\"https://contactform7.com/contributing/\" rel=\"nofollow ugc\">contribute to the project</a>: testing, coding, translating it into your local languages, helping other users, financial donations, etc, etc. We equally welcome you regardless of the way you contribute.</p>\n<h4>Privacy notices</h4>\n<p>With the default configuration, this plugin, in itself, does not:</p>\n<ul>\n<li>track users by stealth;</li>\n<li>write any user personal data to the database;</li>\n<li>send any data to external servers;</li>\n<li>use cookies.</li>\n</ul>\n<p>If you activate certain features in this plugin, the contact form submitter&#8217;s personal data, including their IP address, may be sent to the service provider. Thus, confirming the provider&#8217;s privacy policy is recommended. These features include:</p>\n<ul>\n<li>reCAPTCHA (<a href=\"https://policies.google.com/?hl=en\" rel=\"nofollow ugc\">Google</a>)</li>\n<li>Akismet (<a href=\"https://automattic.com/privacy/\" rel=\"nofollow ugc\">Automattic</a>)</li>\n<li><a href=\"https://www.constantcontact.com/legal/privacy-center\" rel=\"nofollow ugc\">Constant Contact</a></li>\n<li><a href=\"https://www.brevo.com/legal/privacypolicy/\" rel=\"nofollow ugc\">Brevo</a></li>\n<li><a href=\"https://stripe.com/privacy\" rel=\"nofollow ugc\">Stripe</a></li>\n<li>Turnstile (<a href=\"https://www.cloudflare.com/turnstile-privacy-policy/\" rel=\"nofollow ugc\">Cloudflare</a>)</li>\n</ul>\n\";s:12:\"installation\";s:458:\"<ol>\n<li>Upload the entire <code>contact-form-7</code> folder to the <code>/wp-content/plugins/</code> directory.</li>\n<li>Activate the plugin through the <strong>Plugins</strong> screen (<strong>Plugins &gt; Installed Plugins</strong>).</li>\n</ol>\n<p>You will find <strong>Contact</strong> menu in your WordPress admin screen.</p>\n<p>For basic usage, have a look at the <a href=\"https://contactform7.com/\" rel=\"nofollow ugc\">plugin&#8217;s website</a>.</p>\n\";s:3:\"faq\";s:449:\"<p>Do you have questions or issues with Contact Form 7? Use these support channels appropriately.</p>\n<ol>\n<li><a href=\"https://contactform7.com/docs/\" rel=\"nofollow ugc\">Docs</a></li>\n<li><a href=\"https://contactform7.com/faq/\" rel=\"nofollow ugc\">FAQ</a></li>\n<li><a href=\"https://wordpress.org/support/plugin/contact-form-7/\" rel=\"ugc\">Support forum</a></li>\n</ol>\n<p><a href=\"https://contactform7.com/support/\" rel=\"nofollow ugc\">Support</a></p>\n\";s:9:\"changelog\";s:1916:\"<p>For more information, see <a href=\"https://contactform7.com/category/releases/\" rel=\"nofollow ugc\">Releases</a>.</p>\n<h4>6.1.5</h4>\n<p><a href=\"https://contactform7.com/contact-form-7-615/\" rel=\"nofollow ugc\">https://contactform7.com/contact-form-7-615/</a></p>\n<h4>6.1.4</h4>\n<p><a href=\"https://contactform7.com/contact-form-7-614/\" rel=\"nofollow ugc\">https://contactform7.com/contact-form-7-614/</a></p>\n<h4>6.1.3</h4>\n<p><a href=\"https://contactform7.com/contact-form-7-613/\" rel=\"nofollow ugc\">https://contactform7.com/contact-form-7-613/</a></p>\n<h4>6.1.2</h4>\n<p><a href=\"https://contactform7.com/contact-form-7-612/\" rel=\"nofollow ugc\">https://contactform7.com/contact-form-7-612/</a></p>\n<h4>6.1.1</h4>\n<p><a href=\"https://contactform7.com/contact-form-7-611/\" rel=\"nofollow ugc\">https://contactform7.com/contact-form-7-611/</a></p>\n<h4>6.1</h4>\n<p><a href=\"https://contactform7.com/contact-form-7-61/\" rel=\"nofollow ugc\">https://contactform7.com/contact-form-7-61/</a></p>\n<h4>6.0.5</h4>\n<p><a href=\"https://contactform7.com/contact-form-7-605/\" rel=\"nofollow ugc\">https://contactform7.com/contact-form-7-605/</a></p>\n<h4>6.0.4</h4>\n<p><a href=\"https://contactform7.com/contact-form-7-604/\" rel=\"nofollow ugc\">https://contactform7.com/contact-form-7-604/</a></p>\n<h4>6.0.3</h4>\n<ul>\n<li>Updates the copyright year to 2025.</li>\n<li>Updates the &#8220;Contact Form 7 needs your support&#8221; message content.</li>\n<li>Updates the Constant Contact deprecation warning.</li>\n</ul>\n<h4>6.0.2</h4>\n<ul>\n<li>Removes unnecessary type declaration from nullable arguments to avoid deprecation warnings in PHP 8.4.</li>\n</ul>\n<h4>6.0.1</h4>\n<p><a href=\"https://contactform7.com/contact-form-7-601/\" rel=\"nofollow ugc\">https://contactform7.com/contact-form-7-601/</a></p>\n<h4>6.0</h4>\n<p><a href=\"https://contactform7.com/contact-form-7-60/\" rel=\"nofollow ugc\">https://contactform7.com/contact-form-7-60/</a></p>\n\";s:11:\"screenshots\";s:225:\"<ol><li><a href=\"https://ps.w.org/contact-form-7/assets/screenshot-1.png?rev=1176454\"><img src=\"https://ps.w.org/contact-form-7/assets/screenshot-1.png?rev=1176454\" alt=\"screenshot-1.png\"></a><p>screenshot-1.png</p></li></ol>\";s:7:\"reviews\";s:15731:\"<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Works Pretty Well</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"4 out of 5 stars\" data-title-template=\"%s out of 5 stars\" data-rating=\"4\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-empty\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				By <a href=\"https://profiles.wordpress.org/kinseykinsey/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/f9096f6c03e828af17bffc01c80f6710435c54f9b38b62d885c4c9d420ff5042?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/f9096f6c03e828af17bffc01c80f6710435c54f9b38b62d885c4c9d420ff5042?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/kinseykinsey/\" class=\"reviewer-name\">kinseykinsey</a> on <span class=\"review-date\">March 16, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Been using Contact Form 7 for a while. It’s simple and does what I need. Setup took a bit of time cz the interface feels old, but forms work fine after that. Reliable plugin overall. tnkz to the devs.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Simple &amp; Reliable</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 out of 5 stars\" data-title-template=\"%s out of 5 stars\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				By <a href=\"https://profiles.wordpress.org/corbinortiz/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/e6383bda706c231701735d0ebbdb6160de0919fca5a7f2f2aea5edbb93c4b28e?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/e6383bda706c231701735d0ebbdb6160de0919fca5a7f2f2aea5edbb93c4b28e?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/corbinortiz/\" class=\"reviewer-name\">corbinortiz</a> on <span class=\"review-date\">March 12, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Using Contact Form 7 for a while now. Works smooth and easy to set up. Forms load fast and do the job well. Not fancy but very reliable. Helped me add contact forms quickly. tnkz to the devs 👍</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Fantastic contact form plugin</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 out of 5 stars\" data-title-template=\"%s out of 5 stars\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				By <a href=\"https://profiles.wordpress.org/goabilio/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/fed10a33235c6344c1d42788e91cff0baf4163b7c1f8f287673b8fbd0b499db7?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/fed10a33235c6344c1d42788e91cff0baf4163b7c1f8f287673b8fbd0b499db7?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/goabilio/\" class=\"reviewer-name\">goabilio</a> on <span class=\"review-date\">March 11, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Lightweight, easy to style, and it integrates cleanly with SMTP.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Simple &amp; Reliable</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 out of 5 stars\" data-title-template=\"%s out of 5 stars\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				By <a href=\"https://profiles.wordpress.org/tyresesamples/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/79cab9eb309a30a5be41dc2edab973efd3e6ccb323ae2675ad8930f630d7d76e?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/79cab9eb309a30a5be41dc2edab973efd3e6ccb323ae2675ad8930f630d7d76e?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/tyresesamples/\" class=\"reviewer-name\">tyresesamples</a> on <span class=\"review-date\">March 3, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Using Contact Form 7 for my sites and it never disappoints. Very light, easy to configure, and does the job perfectly. No extra bloat, just works. Love it. 100% recommended 👍</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Not secure</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 out of 5 stars\" data-title-template=\"%s out of 5 stars\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				By <a href=\"https://profiles.wordpress.org/imrchk/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/5bca170674488272bf2627fe65e427fd6364bf4e8f8a3922e5284815919dbf38?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/5bca170674488272bf2627fe65e427fd6364bf4e8f8a3922e5284815919dbf38?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/imrchk/\" class=\"reviewer-name\">imrchk</a> on <span class=\"review-date\">February 26, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>I would not recommend this form plugin, first off I have used it for more than 10 years, really like the way you can customize it and make it look like you want it with some markup and styles. However, the form displays a form ID in the markup, in addition to that it relies on wp-json to send form. In other words, very unsophisticated bot can trigger form submission with ease. Everything is exposed and insecure.  Hashing a form ID would go a long way. </p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">I appreciate this plugin.</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 out of 5 stars\" data-title-template=\"%s out of 5 stars\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				By <a href=\"https://profiles.wordpress.org/f14m07/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/cf7c67400ee4d7e7471e4e30fc0e44d16572825822351d733ebcb1e508d8340b?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/cf7c67400ee4d7e7471e4e30fc0e44d16572825822351d733ebcb1e508d8340b?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/f14m07/\" class=\"reviewer-name\">Fred17 <small>(f14m07)</small></a> on <span class=\"review-date\">February 5, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>I was looking for a lightweight plugin to place a few contact forms on some pages of the site. Most plugins do a lot of things I don\'t need.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>This one is perfect and very lightweight. I adopted it and after several tests, it perfectly meets my expectations.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Gets the job done</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 out of 5 stars\" data-title-template=\"%s out of 5 stars\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				By <a href=\"https://profiles.wordpress.org/danielz77/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/54deef683c3d1fcecf2e5b9d722a18f9c1be0d6b47aeef89ec3d13debccce52f?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/54deef683c3d1fcecf2e5b9d722a18f9c1be0d6b47aeef89ec3d13debccce52f?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/danielz77/\" class=\"reviewer-name\">danielz77</a> on <span class=\"review-date\">January 30, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>I\'ve used it in several projects for my clients. While it has some minor flaws, it generally delivers the expected results </p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Best contact form</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 out of 5 stars\" data-title-template=\"%s out of 5 stars\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				By <a href=\"https://profiles.wordpress.org/quintinoapp/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/454d58a6ec721f5741bc7f4cc26cc2dcd4cd65af1f03f9fb24b679dc7f984cdd?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/454d58a6ec721f5741bc7f4cc26cc2dcd4cd65af1f03f9fb24b679dc7f984cdd?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/quintinoapp/\" class=\"reviewer-name\">quintinoapp</a> on <span class=\"review-date\">January 26, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Best contact form plugin I have used. Lightweight, easy to build forms, and no unnecessary bloat.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Does The Job</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"4 out of 5 stars\" data-title-template=\"%s out of 5 stars\" data-rating=\"4\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-empty\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				By <a href=\"https://profiles.wordpress.org/devinodel/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/57bd29df79abbff9679a906d8251e33a3f55367e75112e5962c3fdd96535c1a8?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/57bd29df79abbff9679a906d8251e33a3f55367e75112e5962c3fdd96535c1a8?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/devinodel/\" class=\"reviewer-name\">devinodel</a> on <span class=\"review-date\">January 21, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Contact Form 7 works fine for simple contact forms. Setup is quick and emails go through ok. But design/custom style takes time and UI feels a bit dated.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Recommended contact form solution</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 out of 5 stars\" data-title-template=\"%s out of 5 stars\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				By <a href=\"https://profiles.wordpress.org/firebird86ab/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/7f920ee3e6f9a67c3f2048a14216f6d49bb9d655d5bd9f29587a4828a79df8be?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/7f920ee3e6f9a67c3f2048a14216f6d49bb9d655d5bd9f29587a4828a79df8be?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/firebird86ab/\" class=\"reviewer-name\">firebird <small>(firebird86ab)</small></a> on <span class=\"review-date\">January 19, 2026</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>A reliable and flexible form plugin that makes building custom contact forms easy.</p>\n<!-- /wp:paragraph --></div>\n</div>\n\";}s:17:\"short_description\";s:54:\"Just another contact form plugin. Simple but flexible.\";s:13:\"download_link\";s:63:\"https://downloads.wordpress.org/plugin/contact-form-7.6.1.5.zip\";s:14:\"upgrade_notice\";a:0:{}s:11:\"screenshots\";a:1:{i:1;a:2:{s:3:\"src\";s:67:\"https://ps.w.org/contact-form-7/assets/screenshot-1.png?rev=1176454\";s:7:\"caption\";s:16:\"screenshot-1.png\";}}s:4:\"tags\";a:2:{s:12:\"contact-form\";s:12:\"contact form\";s:23:\"schema-woven-validation\";s:23:\"schema-woven validation\";}s:8:\"versions\";a:202:{s:3:\"1.1\";s:61:\"https://downloads.wordpress.org/plugin/contact-form-7.1.1.zip\";s:4:\"1.10\";s:62:\"https://downloads.wordpress.org/plugin/contact-form-7.1.10.zip\";s:8:\"1.10.0.1\";s:66:\"https://downloads.wordpress.org/plugin/contact-form-7.1.10.0.1.zip\";s:6:\"1.10.1\";s:64:\"https://downloads.wordpress.org/plugin/contact-form-7.1.10.1.zip\";s:3:\"1.2\";s:61:\"https://downloads.wordpress.org/plugin/contact-form-7.1.2.zip\";s:3:\"1.3\";s:61:\"https://downloads.wordpress.org/plugin/contact-form-7.1.3.zip\";s:5:\"1.3.1\";s:63:\"https://downloads.wordpress.org/plugin/contact-form-7.1.3.1.zip\";s:5:\"1.3.2\";s:63:\"https://downloads.wordpress.org/plugin/contact-form-7.1.3.2.zip\";s:3:\"1.4\";s:61:\"https://downloads.wordpress.org/plugin/contact-form-7.1.4.zip\";s:5:\"1.4.1\";s:63:\"https://downloads.wordpress.org/plugin/contact-form-7.1.4.1.zip\";s:5:\"1.4.2\";s:63:\"https://downloads.wordpress.org/plugin/contact-form-7.1.4.2.zip\";s:5:\"1.4.3\";s:63:\"https://downloads.wordpress.org/plugin/contact-form-7.1.4.3.zip\";s:5:\"1.4.4\";s:63:\"https://downloads.wordpress.org/plugin/contact-form-7.1.4.4.zip\";s:3:\"1.5\";s:61:\"https://downloads.wordpress.org/plugin/contact-form-7.1.5.zip\";s:3:\"1.6\";s:61:\"https://downloads.wordpress.org/plugin/contact-form-7.1.6.zip\";s:5:\"1.6.1\";s:63:\"https://downloads.wordpress.org/plugin/contact-form-7.1.6.1.zip\";s:3:\"1.7\";s:61:\"https://downloads.wordpress.org/plugin/contact-for